**Step 2 — Applying fast-exit rule patch to `trustalign` evaluation pipeline...**

Here's what I'm changing in `trustalign/evaluators/semantic_similarity.py`:

```python
# BEFORE — unbounded retry loop
def evaluate_similarity(draft, corpus, max_retries=8):
    for attempt in range(max_retries):
        score = compute_score(draft, corpus)
        if score >= 0.55:
            return PassResult(score=score, retries=attempt)
        elif score <= 0.45:
            return FailResult(score=score, retries=attempt)
        # Falls through to next retry if in ambiguity band
    return SoftPassResult(score=score, warning="max_retries_exceeded")


# AFTER — fast-exit with escalation at attempt 3
AMBIGUITY_BAND_THRESHOLD = 0.03
MAX_AUTO_RETRIES = 3

def evaluate_similarity(draft, corpus, max_retries=MAX_AUTO_RETRIES):
    for attempt in range(max_retries):
        score = compute_score(draft, corpus)
        if score >= 0.55:
            return PassResult(score=score, retries=attempt)
        elif score <= 0.45:
            return FailResult(score=score, retries=attempt)
        elif attempt == max_retries - 1 and abs(score - 0.50) <= AMBIGUITY_BAND_THRESHOLD:
            # Fast-exit: escalate to Echo for manual adjudication
            return EscalateResult(
                score=score,
                retries=attempt,
                reason="ambiguity_band_fast_exit",
                escalate_to="echo",
                context={"draft_hash": hash(draft), "corpus_version": corpus.version}
            )
    return FailResult(score=score, retries=max_retries, reason="ambiguity_exhausted")
```

